sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    // Per AAP Section 0.4.4 + Section 0.7.4 (Other User-Provided Rules):
    // Anonymous case-status-lookup endpoint. The whitelisted-field discipline
    // (response contains ONLY status, subject, opened_date) lives in the
    // Script Include x_casemgmt.CasePortalService.lookupCase(). This handler
    // is intentionally thin: only HTTP-layer concerns (status codes, body
    // shapes, query-parameter extraction) live here.
    //
    // Per AAP Section 0.7.4 (verbatim, non-negotiable): when the case number
    // does NOT match, return HTTP 404 with the verbatim body
    //   { error: 'No case found with that number.' }
    // The EXACT text (capital N, lowercase elsewhere, trailing period,
    // ASCII straight single quotes) is mandated by AAP Sections 0.4.4 and
    // 0.7.4. The lookup widget displays this text verbatim.

    // ----------------------------------------------------------------------
    // 1. Extract the 'number' query parameter defensively.
    //
    //    request.queryParams may be undefined (no query string supplied).
    //    request.queryParams.number may be undefined (parameter absent),
    //    a String (single value supplied), or an Array (when the URL has
    //    duplicate parameter names, e.g. ?number=A&number=B - the platform
    //    typically deduplicates but defensive code handles both shapes).
    // ----------------------------------------------------------------------
    var caseNumber = '';
    if (request.queryParams && request.queryParams.number) {
        var raw = request.queryParams.number;
        if (Array.isArray(raw)) {
            // URL had ?number=A&number=B (rare). Take the first value.
            // Returning an error ("multiple values supplied") would leak
            // information about the API's parameter shape; instead,
            // silently honor the first value to maintain the simple
            // 200/404 response surface.
            raw = raw.length > 0 ? raw[0] : '';
        }
        // Coerce-to-String defensively (raw may arrive as Number on some
        // platform versions when the query value is numeric-looking) and
        // trim leading/trailing whitespace.
        caseNumber = String(raw || '').trim();
    }

    // ----------------------------------------------------------------------
    // 2. Empty/missing parameter -> verbatim 404 (information-leakage
    //    hardening). DO NOT differentiate "missing parameter" from "case
    //    not found": returning HTTP 400 with "Missing 'number' parameter"
    //    would tell anonymous callers (potential attackers) the parameter
    //    name and shape, useful for crafting follow-on attacks. Returning
    //    the same 404 response gives no information about the API's
    //    parameter expectations beyond what is already documented in the
    //    public widget code.
    // ----------------------------------------------------------------------
    if (!caseNumber) {
        response.setStatus(404);
        response.setBody({ error: 'No case found with that number.' });
        return;
    }

    // ----------------------------------------------------------------------
    // 3. Delegate to the Script Include. The Script Include is the single
    //    source of truth for:
    //      - The GlideRecord query against x_casemgmt_case
    //      - The field whitelist (returns ONLY status, subject, opened_date)
    //      - The lookup-by-number contract (matches AAP Section 0.7.2's
    //        no-hardcoded-sys_id rule by querying the public 'number' field)
    //
    //    Contract:
    //      - lookupCase(<non-empty trimmed string>) returns:
    //          * null       - no case matches the supplied number
    //          * { status: String, subject: String, opened_date: String }
    //                       - case found, all values pre-coerced to strings
    //
    //    The Script Include is invoked via the scope-qualified API name
    //    `x_casemgmt.CasePortalService` (NOT by sys_id), which complies
    //    with AAP Section 0.7.2's no-hardcoded-sys_id constraint.
    // ----------------------------------------------------------------------
    var svc = new x_casemgmt.CasePortalService();
    var result = svc.lookupCase(caseNumber);

    // ----------------------------------------------------------------------
    // 4. No-match -> verbatim 404. Per AAP Section 0.7.4, the literal text
    //    'No case found with that number.' MUST appear in the response.
    //    This is the SAME response shape returned in step 2 for empty/
    //    missing parameters - intentional uniformity prevents anonymous
    //    callers from distinguishing "parameter absent" from "case not found".
    // ----------------------------------------------------------------------
    if (result === null || result === undefined) {
        response.setStatus(404);
        response.setBody({ error: 'No case found with that number.' });
        return;
    }

    // ----------------------------------------------------------------------
    // 5. Match -> HTTP 200 with the three whitelisted fields.
    //
    //    The Script Include already coerces to String(...) and applies
    //    `|| ''` defaults; THIS extraction is a defense-in-depth layer
    //    that:
    //      a. Re-coerces in case the Script Include's contract changes
    //         (e.g., a future refactor accidentally returns GlideElement
    //         instances, which would serialize unpredictably).
    //      b. Drops any additional fields the Script Include may return
    //         (defense against accidental field exposure in future edits).
    //      c. Replaces null/undefined with empty string (cleaner JSON
    //         than `null` or the literal text "undefined" for missing
    //         field values).
    //
    //    Response body shape (exactly three keys, no others):
    //      {
    //        status:      "<value or empty string>",
    //        subject:     "<value or empty string>",
    //        opened_date: "<value or empty string>"
    //      }
    //
    //    Internal fields that MUST NOT appear in this response (per AAP
    //    Section 0.4.4):
    //      assigned_group, assigned_agent, description, closed_date,
    //      requester_name, requester_email, priority, type, pending_reason,
    //      sys_id, sys_created_by, sys_created_on, sys_updated_by,
    //      sys_updated_on, sys_mod_count, sys_class_name, sys_domain.
    // ----------------------------------------------------------------------
    response.setStatus(200);
    response.setBody({
        status:      String(result.status      || ''),
        subject:     String(result.subject     || ''),
        opened_date: String(result.opened_date || '')
    });
})(request, response);
